    replica:
      jdbc-url: jdbc:mysql://mydb.cluster-ro-abc.us-east-1.rds.amazonaws.com:3306/appdb
      username: ${RDS_USER}
      password: ${RDS_PASSWORD}
      hikari:
        maximum-pool-size: 40    # replicas handle more concurrent reads
        minimum-idle: 5
