// ── Routing DataSource — picks primary or replica per thread ──────
import org.springframework.jdbc.datasource.lookup.AbstractRoutingDataSource;

public class ReplicaRoutingDataSource extends AbstractRoutingDataSource {
    public enum DataSourceType { PRIMARY, REPLICA }

    private static final ThreadLocal<DataSourceType> context = new ThreadLocal<>();
    public static void usePrimary() { context.set(DataSourceType.PRIMARY); }
    public static void useReplica()  { context.set(DataSourceType.REPLICA); }
    public static void clear()       { context.remove(); }

    @Override
    protected Object determineCurrentLookupKey() {
        return context.get() == null ? DataSourceType.PRIMARY : context.get();
    }
}

// ── AOP Aspect — auto-routes @Transactional(readOnly=true) ────────
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.*;
import org.springframework.stereotype.Component;
import org.springframework.transaction.annotation.Transactional;

@Aspect
@Component
public class ReplicaRoutingAspect {
    @Around("@annotation(tx)")
    public Object route(ProceedingJoinPoint pjp, Transactional tx) throws Throwable {
        if (tx.readOnly()) {
            ReplicaRoutingDataSource.useReplica();
            try   { return pjp.proceed(); }
            finally { ReplicaRoutingDataSource.clear(); }
        }
        return pjp.proceed();
    }
}

// ── Service — readOnly=true auto-routes to replica ─────────────────
import org.springframework.stereotype.Service;

@Service
public class TopicService {
    private final TopicRepository repo;
    TopicService(TopicRepository r) { this.repo = r; }

    // REPLICA route — read-heavy, slightly stale is fine
    @Transactional(readOnly = true)
    public List<Topic> getAllTopics() { return repo.findAll(); }

    // PRIMARY route — writes must be consistent
    @Transactional
    public Topic createTopic(TopicDto dto) { return repo.save(new Topic(dto)); }
}

// ── Critical parameters to change in your RDS parameter group ────
/*
1. innodb_buffer_pool_size (MOST IMPACTFUL — restart required)
   Default: 128MB — catastrophically small for production
   Rule: 70-80% of total instance RAM
   db.t3.medium (4GB RAM):  set to 3GB
   db.r5.large  (16GB RAM): set to 12GB
   Why: InnoDB caches index pages here. If buffer pool hit ratio < 95%,
        every cache miss = disk I/O = slow query.

2. max_connections (RAM-based formula)
   Formula: max_connections = RAM_in_MB / 12.5
   db.t3.medium (4096MB):  ~300 connections
   db.r5.large  (16384MB): ~1200 connections
   Note: RDS Proxy can multiplex 1000 Lambda functions onto 100 DB connections.

3. slow_query_log = 1, long_query_time = 1
   log_queries_not_using_indexes = 1  ← most valuable flag
   Routes to CloudWatch Logs: /aws/rds/instance/{name}/slowquery

4. innodb_log_file_size = 1G  (default 48MB — too small for write-heavy)
   Larger log = fewer checkpoints = faster write throughput

5. query_cache_type = 0  (MySQL 5.7 only — disable!
   Query cache = global mutex on every write = performance killer at scale)
*/

// ── CloudWatch alarms to set on every RDS instance ────────────────
/*
Metric                     Threshold         Action
─────────────────────────────────────────────────────────────────────
CPUUtilization             > 80%             Scale up or optimize queries
DatabaseConnections        > maxConnections   Check for connection leaks
                             * 0.8           or add RDS Proxy
FreeStorageSpace           < 20% of total    Enable storage auto-scaling
ReplicaLag                 > 30000 ms        Investigate replica worker
BufferCacheHitRatio        < 0.95            Increase instance size
ReadLatency                > 20 ms           Check IOPS, consider io2
WriteLatency               > 10 ms           Check IOPS, redo log size
FreeableMemory             < 512 MB          Memory pressure — scale up
*/

// ── Java helper: read-after-write consistency window ─────────────
public class ReplicaConsistencyGuard {
    // After a write, route reads to primary for this many ms
    // to avoid reading stale data from a lagging replica.
    private static final long CONSISTENCY_WINDOW_MS = 500;

    public static boolean routeToPrimary(long lastWriteEpochMs) {
        return System.currentTimeMillis() - lastWriteEpochMs < CONSISTENCY_WINDOW_MS;
    }

    public static void main(String[] args) throws InterruptedException {
        long writeTime = System.currentTimeMillis();

        // Immediately after write — use primary for consistency
        System.out.println("Right after write → primary: " + routeToPrimary(writeTime));

        Thread.sleep(600);
        // 600ms later — safe to use replica
        System.out.println("600ms later → primary: " + routeToPrimary(writeTime));
    }
}

