import java.util.*;
import java.util.concurrent.atomic.*;

public class Q1 {
    static class DbEndpoint {
        final String host;
        boolean healthy = true;
        DbEndpoint(String host) { this.host = host; }
    }

    static class ReadWriteRouter {
        private DbEndpoint primary;
        private final List<DbEndpoint> replicas;
        private final AtomicInteger counter = new AtomicInteger(0);

        ReadWriteRouter(DbEndpoint primary, List<DbEndpoint> replicas) {
            this.primary = primary;
            this.replicas = new ArrayList<>(replicas);
        }

        String route(boolean readOnly) {
            if (!readOnly || replicas.isEmpty()) return primary.host;
            int idx = counter.getAndIncrement() % replicas.size();
            return replicas.get(idx).host;
        }

        void failover() {
            primary.healthy = false;
            if (!replicas.isEmpty()) {
                primary = replicas.remove(0);
                primary.healthy = true;
            }
        }
    }

    public static void main(String[] args) {
        DbEndpoint primary = new DbEndpoint("primary.rds.aws.com");
        List<DbEndpoint> replicas = List.of(
            new DbEndpoint("replica1.rds.aws.com"),
            new DbEndpoint("replica2.rds.aws.com")
        );
        ReadWriteRouter router = new ReadWriteRouter(primary, replicas);

        System.out.println(router.route(false));
        System.out.println(router.route(true));
        System.out.println(router.route(true));
        System.out.println(router.route(true));
        router.failover();
        System.out.println(router.route(false));
    }
}

