import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Q2 {
    static class BoundedConnectionPool {
        private final BlockingQueue<String> pool;
        private final AtomicInteger timeouts = new AtomicInteger(0);

        BoundedConnectionPool(int maxSize) {
            this.pool = new ArrayBlockingQueue<>(maxSize);
            for (int i = 1; i <= maxSize; i++) pool.offer("conn-" + i);
        }

        String acquire(long timeoutMs) throws InterruptedException {
            String conn = pool.poll(timeoutMs, TimeUnit.MILLISECONDS);
            if (conn == null) {
                timeouts.incrementAndGet();
                throw new RuntimeException("Pool timeout after " + timeoutMs + "ms");
            }
            return conn;
        }

        void release(String conn) { pool.offer(conn); }

        int available() { return pool.size(); }
        int timeoutCount() { return timeouts.get(); }
    }

    public static void main(String[] args) throws Exception {
        BoundedConnectionPool pool = new BoundedConnectionPool(3);
        System.out.println("Available: " + pool.available());

        String c1 = pool.acquire(100);
        String c2 = pool.acquire(100);
        String c3 = pool.acquire(100);
        System.out.println("After 3 acquired: " + pool.available());

        pool.release(c1);
        System.out.println("After release: " + pool.available());

        pool.acquire(100);
        try {
            pool.acquire(50);
        } catch (RuntimeException e) {
            System.out.println("Timeouts: " + pool.timeoutCount());
        }
    }
}

