public class Q3 {
    static class RdsNode {
        final String endpoint;
        boolean healthy = true;
        RdsNode(String ep) { this.endpoint = ep; }

        String execute(String sql) {
            if (!healthy) throw new RuntimeException("Cannot connect to " + endpoint);
            return "[" + endpoint + "] " + sql + " OK";
        }
    }

    static class MultiAzClient {
        private final RdsNode primary;
        private final RdsNode standby;
        private RdsNode active;

        MultiAzClient(RdsNode p, RdsNode s) {
            this.primary = p; this.standby = s; this.active = p;
        }

        String execute(String sql) {
            try {
                return active.execute(sql);
            } catch (RuntimeException e) {
                if (active == primary && standby.healthy) {
                    System.out.println("Failover to: " + standby.endpoint);
                    active = standby;
                    return active.execute(sql);
                }
                throw e;
            }
        }
    }

    public static void main(String[] args) {
        RdsNode primary = new RdsNode("db-primary.us-east-1a.rds.aws.com");
        RdsNode standby = new RdsNode("db-standby.us-east-1b.rds.aws.com");
        MultiAzClient db = new MultiAzClient(primary, standby);

        System.out.println(db.execute("SELECT 1"));
        primary.healthy = false;
        System.out.println(db.execute("SELECT * FROM users LIMIT 1"));
        System.out.println(db.execute("INSERT INTO events VALUES(?)"));
    }
}
